mapper.select:
/* 카테고리 목록 조회 repository.selectCategoryList */ WITH RECURSIVE CAT_TREE AS ( -- 루트 SELECT CATEGORY_ID, CATEGORY_NAME, PARN_CAT_ID, CAT_LVL, SORT_ORD, CAST(LPAD(SORT_ORD, 10, '0') AS CHAR(2000)) AS SORT_PATH, 1 AS DEPTH FROM TB_CONTENT_CAT WHERE PARN_CAT_ID IS NULL
UNION ALL
-- 자식 (부모가 트리에 있을 때만) SELECT C.CATEGORY_ID, C.CATEGORY_NAME, C.PARN_CAT_ID, C.CAT_LVL, C.SORT_ORD, CONCAT(CT.SORT_PATH, '.', LPAD(C.SORT_ORD, 10, '0')), CT.DEPTH + 1 FROM TB_CONTENT_CAT C INNER JOIN CAT_TREE CT ON C.PARN_CAT_ID = CT.CATEGORY_ID ) SELECT * FROM CAT_TREE ORDER BY SORT_PATH

/* RAG 지식원천 문서 목록 조회 repository.selectDocRepositoryList 선택한 카테고리에 직접 속한 문서만 조회, CATEGORY_NAME = 상위 > ... > 현재 경로 */ SELECT A.DOC_ID , A.DOC_TITLE , A.CATEGORY_ID , ( WITH RECURSIVE CAT_UP AS ( SELECT CATEGORY_ID, CATEGORY_NAME, PARN_CAT_ID, 1 AS DEPTH FROM TB_CONTENT_CAT WHERE CATEGORY_ID = A.CATEGORY_ID UNION ALL SELECT C.CATEGORY_ID, C.CATEGORY_NAME, C.PARN_CAT_ID, CU.DEPTH + 1 FROM TB_CONTENT_CAT C INNER JOIN CAT_UP CU ON C.CATEGORY_ID = CU.PARN_CAT_ID ) SELECT GROUP_CONCAT(CU.CATEGORY_NAME ORDER BY CU.DEPTH DESC SEPARATOR ' > ') FROM CAT_UP CU ) AS CATEGORY_NAME , A.AUTHOR , A.SEC_LVL , A.CONTENT , A.KEYWORDS , A.REF_URL , A.USE_YN , A.CREATE_DT , A.MODIFY_DT , ( SELECT SUM(B.FILE_SIZE) FROM TB_DOC_FILE B WHERE 1 = 1 AND B.DOC_ID = A.DOC_ID ) AS FILE_SIZE , ( SELECT COUNT(*) FROM TB_DS_DOC B WHERE 1=1 AND B.DOC_ID = A.DOC_ID ) AS DS_DOC_CNT , ( SELECT COUNT(*) FROM TB_DOC_FILE B WHERE 1=1 AND B.DOC_ID = A.DOC_ID ) AS FILE_CNT , ( SELECT GROUP_CONCAT(F.DOC_FILE_ID ORDER BY F.FILE_ORD SEPARATOR ',') FROM TB_DOC_FILE F WHERE F.DOC_ID = A.DOC_ID ) AS DOC_FILE_ID_LIST , ( SELECT GROUP_CONCAT(C.DS_NM ORDER BY F.DATASET_ID SEPARATOR ', ') FROM TB_DS_DOC F INNER JOIN TB_DS C ON C.DATASET_ID = F.DATASET_ID WHERE F.DOC_ID = A.DOC_ID ) AS DS_NM_LIST FROM TB_DOC A WHERE 1=1
AND A.CATEGORY_ID = #{categoryId}
AND ( A.CONTENT LIKE CONCAT('%', #{findContent}, '%') OR A.DOC_TITLE LIKE CONCAT('%', #{findContent}, '%') )
AND A.USE_YN = #{useYn}
ORDER BY A.DOC_ID DESC

/* RAG 지식원천 문서 목록 조회 repository.selectDocRepositoryListCnt 선택한 카테고리에 직접 속한 문서만 집계 (목록과 동일 조건) */ SELECT COUNT(*) AS TOTAL_COUNT FROM TB_DOC A WHERE 1=1 AND A.USE_YN = 'Y'
AND A.CATEGORY_ID = #{categoryId}
AND ( A.CONTENT LIKE CONCAT('%', #{findContent}, '%') OR A.DOC_TITLE LIKE CONCAT('%', #{findContent}, '%') )
ORDER BY A.DOC_ID DESC

/* 문서 존재 여부 조회 repository.selectDocExistCnt */ SELECT COUNT(*) AS CNT FROM TB_DOC_FILE A LEFT OUTER JOIN TB_DOC B ON B.DOC_ID = A.DOC_ID WHERE 1 = 1 AND A.USE_YN = 'Y' AND (B.CATEGORY_ID, A.FILE_NAME) IN (
(#{item.categoryId}, #{item.fileName})
)

