mapper.insert:
/* 문서 저장(등록/수정) repository.saveDocument */
INSERT INTO TB_DOC (
    DOC_ID
    , DOC_TITLE
    , CATEGORY_ID
    , AUTHOR
    , SEC_LVL
    , CONTENT
    , KEYWORDS
    , REF_URL
    , USE_YN
    , CREATE_DT
    , CREATE_USER_ID
    , MODIFY_DT
    , MODIFY_USER_ID
) VALUES (
    #{docId}
    , #{docTitle, jdbcType=VARCHAR}
    , #{categoryId, jdbcType=VARCHAR}
    , #{author, jdbcType=VARCHAR}
    , #{secLvl, jdbcType=VARCHAR}
    , #{content, jdbcType=LONGVARCHAR}
    , #{keywords, jdbcType=VARCHAR}
    , #{refUrl, jdbcType=VARCHAR}
    , #{useYn, jdbcType=CHAR}
    , NOW()
    , #{createUserId, jdbcType=VARCHAR}
    , NOW()
    , #{createUserId, jdbcType=VARCHAR}
)

mapper.update:
/* 문서 수정 repository.updateDocument */
UPDATE TB_DOC
SET DOC_TITLE = #{docTitle, jdbcType=VARCHAR}
    , CATEGORY_ID = #{categoryId, jdbcType=VARCHAR}
    , AUTHOR = #{author, jdbcType=VARCHAR}
    , SEC_LVL = #{secLvl, jdbcType=VARCHAR}
    , CONTENT = #{content, jdbcType=LONGVARCHAR}
    , KEYWORDS = #{keywords, jdbcType=VARCHAR}
    , REF_URL = #{refUrl, jdbcType=VARCHAR}
    , USE_YN = #{useYn, jdbcType=CHAR}
    , MODIFY_DT = NOW()
    , MODIFY_USER_ID = #{modifyUserId, jdbcType=VARCHAR}
WHERE DOC_ID = #{docId, jdbcType=VARCHAR}

mapper.insert:
/* 문서 파일 저장 repository.saveDocumentFile */
INSERT INTO TB_DOC_FILE (
    DOC_FILE_ID
    , DOC_ID
    , FILE_NAME
    , FILE_PATH
    , FILE_SIZE
    , FILE_TYPE
    , FILE_ORD
    , USE_YN
    , CREATE_DT
    , MODIFY_DT
)
SELECT
    #{docFileId, jdbcType=VARCHAR}
    , #{docId, jdbcType=VARCHAR}
    , #{fileName, jdbcType=VARCHAR}
    , #{filePath, jdbcType=VARCHAR}
    , #{fileSize, jdbcType=BIGINT}
    , #{fileType, jdbcType=VARCHAR}
    , #{fileOrd, jdbcType=INTEGER}
    , #{useYn, jdbcType=CHAR}
    , NOW()
    , NOW()
FROM DUAL
WHERE NOT EXISTS (
    SELECT 1
    FROM TB_DOC_FILE
    WHERE DOC_ID = #{docId, jdbcType=VARCHAR}
      AND FILE_PATH = #{filePath, jdbcType=VARCHAR}
      AND USE_YN = 'Y'
)

