/* 문서 파일 최대 순번 조회 repository.selectMaxFileOrdByDocId */
SELECT COALESCE(MAX(FILE_ORD), 0)
FROM TB_DOC_FILE
WHERE DOC_ID = #{docId, jdbcType=VARCHAR}

